import { useState } from "react";
import AppShell from "../components/AppShell";
import AlertCard from "../components/AlertCard";
import EmptyState from "../components/EmptyState";
import { FormField } from "../components/FormField";
import InsightPanel from "../components/InsightPanel";
import MetricCard from "../components/MetricCard";
import PageHeader from "../components/PageHeader";
import PrimaryButton from "../components/PrimaryButton";
import SectionCard from "../components/SectionCard";
import TrendChartCard from "../components/TrendChartCard";
import { useVitalPulse } from "../context/VitalPulseContext";
import {
  formatDateTime,
  formatMetric,
  formatRelativeTime,
} from "../utils/formatters";

const initialForm = {
  patient_id: "",
  device_id: "",
  heart_rate: "",
  temperature: "",
  spo2: "",
  anomaly_score: "",
  status: "normal",
  timestamp: "",
};

function readingState(latestReading, derived) {
  if (!latestReading) return "Waiting for live data";
  if (derived.deviceState === "Stale") return "Device offline";
  return "Realtime telemetry active";
}

export default function LiveMonitorPage() {
  const { latestReading, trendSamples, alerts, submitManualReading, derived } = useVitalPulse();
  const [form, setForm] = useState(initialForm);
  const [submitting, setSubmitting] = useState(false);
  const [formMessage, setFormMessage] = useState("");

  async function handleSubmit(event) {
    event.preventDefault();
    setSubmitting(true);
    setFormMessage("");
    try {
      await submitManualReading({
        device_id: form.device_id,
        heart_rate: Number(form.heart_rate),
        spo2: Number(form.spo2),
        temperature: Number(form.temperature),
        anomaly_score: Number(form.anomaly_score || 0),
        status: form.status,
        timestamp: form.timestamp
          ? new Date(form.timestamp).toISOString()
          : new Date().toISOString(),
      });
      setFormMessage("Reading submitted to ingest API.");
      setForm(initialForm);
    } catch (error) {
      setFormMessage(`Submission failed: ${error.message}`);
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <AppShell topbarAction={<PrimaryButton icon="spark" disabled>Summary with AI</PrimaryButton>}>
      <PageHeader
        title="Live Monitoring"
        subtitle="Streaming patient telemetry, anomaly score, and system health."
        actions={
          <div className="vp-inline-field">
            <FormField label="Patient selector">
              <select className="vp-input" disabled>
                <option>Patient directory endpoint required</option>
              </select>
            </FormField>
          </div>
        }
      />

      <div className="vp-grid vp-grid-metrics">
        <MetricCard icon="heart" label="Heart Rate" value={latestReading ? formatMetric(latestReading.heart_rate, "bpm") : "Waiting for live data"} helper={readingState(latestReading, derived)} status={latestReading?.status || "Pending"} />
        <MetricCard icon="temp" label="Temperature" value={latestReading ? formatMetric(latestReading.temperature, "deg C") : "No reading received"} helper={formatDateTime(latestReading?.timestamp)} status={latestReading ? "Loaded" : "Pending"} />
        <MetricCard icon="spo2" label="SpO2" value={latestReading ? formatMetric(latestReading.spo2, "%") : "Device offline"} helper="Peripheral oxygen saturation" status={latestReading ? "Loaded" : "Pending"} />
        <MetricCard icon="risk" label="Risk" value={derived.riskLabel} helper={latestReading ? `Anomaly score ${latestReading.anomaly_score}` : "Awaiting live model output"} status={derived.riskLabel} accent="ai" />
        <MetricCard icon="device" label="Signal quality" value={derived.deviceState === "Online" ? "Telemetry healthy" : "No recent signal"} helper="Derived from sample freshness" status={derived.deviceState} />
        <MetricCard icon="clock" label="Last reading" value={latestReading ? formatRelativeTime(latestReading.timestamp) : "No live timestamp"} helper={latestReading ? formatDateTime(latestReading.timestamp) : "Waiting for first reading"} status={latestReading ? "Loaded" : "Pending"} />
      </div>

      <div className="vp-grid vp-grid-analytics">
        <TrendChartCard title="Heart rate trend" subtitle="Realtime monitoring line." samples={trendSamples} dataKey="heart_rate" />
        <TrendChartCard title="Temperature trend" subtitle="Live temperature history." samples={trendSamples} dataKey="temperature" stroke="var(--warning)" />
        <TrendChartCard title="SpO2 trend" subtitle="Oxygen saturation trend." samples={trendSamples} dataKey="spo2" stroke="var(--info)" />
        <TrendChartCard title="Risk and anomaly trend" subtitle="Model score history." samples={trendSamples} dataKey="anomaly_score" stroke="var(--ai)" />
      </div>

      <div className="vp-content-with-panel">
        <div className="vp-content-main">
          <SectionCard title="Manual Test Entry" subtitle="Admin-only telemetry injection for test and validation workflows.">
            <form className="vp-form-grid" onSubmit={handleSubmit}>
              <FormField label="Patient selector" hint="No patient endpoint currently exists.">
                <input className="vp-input" value={form.patient_id} onChange={(event) => setForm((current) => ({ ...current, patient_id: event.target.value }))} placeholder="Optional local patient reference" />
              </FormField>
              <FormField label="Device ID">
                <input className="vp-input" required value={form.device_id} onChange={(event) => setForm((current) => ({ ...current, device_id: event.target.value }))} placeholder="e.g. sensor-01" />
              </FormField>
              <FormField label="Heart rate">
                <input className="vp-input" required type="number" value={form.heart_rate} onChange={(event) => setForm((current) => ({ ...current, heart_rate: event.target.value }))} />
              </FormField>
              <FormField label="Temperature">
                <input className="vp-input" required type="number" step="0.1" value={form.temperature} onChange={(event) => setForm((current) => ({ ...current, temperature: event.target.value }))} />
              </FormField>
              <FormField label="SpO2">
                <input className="vp-input" required type="number" step="0.1" value={form.spo2} onChange={(event) => setForm((current) => ({ ...current, spo2: event.target.value }))} />
              </FormField>
              <FormField label="Signal quality / score">
                <input className="vp-input" type="number" step="0.01" value={form.anomaly_score} onChange={(event) => setForm((current) => ({ ...current, anomaly_score: event.target.value }))} placeholder="0.0 - 1.0" />
              </FormField>
              <FormField label="Status">
                <select className="vp-input" value={form.status} onChange={(event) => setForm((current) => ({ ...current, status: event.target.value }))}>
                  <option value="normal">Normal</option>
                  <option value="warning">Warning</option>
                  <option value="critical">Critical</option>
                </select>
              </FormField>
              <FormField label="Timestamp">
                <input className="vp-input" type="datetime-local" value={form.timestamp} onChange={(event) => setForm((current) => ({ ...current, timestamp: event.target.value }))} />
              </FormField>
              <div className="vp-form-actions">
                <PrimaryButton type="submit" disabled={submitting}>
                  {submitting ? "Submitting..." : "Submit Reading"}
                </PrimaryButton>
                {formMessage ? <p className="vp-form-message">{formMessage}</p> : null}
              </div>
            </form>
          </SectionCard>

          <SectionCard title="Facility Runtime" subtitle="Runtime state available from current backend telemetry.">
            <div className="vp-health-grid">
              <div className="vp-health-item"><span>Device connection</span><strong>{derived.deviceState}</strong></div>
              <div className="vp-health-item"><span>Node-RED</span><strong>Endpoint required</strong></div>
              <div className="vp-health-item"><span>Database</span><strong>Endpoint required</strong></div>
              <div className="vp-health-item"><span>ML Engine</span><strong>{derived.mlAvailable ? "Loaded" : "Awaiting ML score"}</strong></div>
              <div className="vp-health-item"><span>Latest timestamp</span><strong>{formatDateTime(latestReading?.timestamp)}</strong></div>
            </div>
          </SectionCard>

          <SectionCard title="Recent Alerts" subtitle="Alerts relevant to the currently selected monitoring context.">
            {alerts.length ? (
              <div className="vp-list-stack">
                {alerts.slice(0, 3).map((alert) => <AlertCard key={alert.id} alert={alert} />)}
              </div>
            ) : (
              <EmptyState title="No patient-linked alerts yet" message="The monitoring backend has not returned any active alerts for this context." icon="alerts" />
            )}
          </SectionCard>
        </div>

        <InsightPanel
          title="Patient Context"
          subtitle="Clinical context for the currently observed stream."
          items={[
            { label: "Selected patient", value: "Patient endpoint required", status: "Pending" },
            { label: "Assigned device", value: derived.liveDeviceId || "No device observed", status: derived.deviceState },
            { label: "Last seen", value: latestReading ? formatRelativeTime(latestReading.timestamp) : "No reading received", status: latestReading ? "Loaded" : "Pending" },
            { label: "Risk level", value: derived.riskLabel, status: derived.riskLabel },
            { label: "Latest anomaly reason", value: derived.mlAvailable ? "ML output available" : "Model endpoint required", status: derived.mlAvailable ? "Loaded" : "Pending" },
            { label: "Monitoring status", value: readingState(latestReading, derived), status: derived.deviceState },
          ]}
          footer="Patient identity, facility assignment, and structured clinical context require dedicated patient APIs."
        />
      </div>
    </AppShell>
  );
}
